import{_ as e,c as r,o,a4 as a}from"./chunks/framework.CzsDe1xi.js";const b=JSON.parse('{"title":"kube-controller-manager","description":"","frontmatter":{"title":"kube-controller-manager","order":1},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/kube-controller-manager/index.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/kube-controller-manager/index.md","lastUpdated":1704901837000}'),n={name:"doc/DevOps/Kubernetes/基础/kube-controller-manager/index.md"},t=a('<h1 id="kube-controller-manager" tabindex="-1">kube-controller-manager <a class="header-anchor" href="#kube-controller-manager" aria-label="Permalink to &quot;kube-controller-manager&quot;">​</a></h1><ul><li><a href="https://kubernetes.io/zh-cn/docs/reference/command-line-tools-reference/kube-controller-manager/" target="_blank" rel="noreferrer">官方文档</a> kube-controller-manager 是控制平面的组件， 负责运行控制器进程。</li></ul><p>Controller Manager作为集群内部的管理控制中心，负责集群内Node、Pod副本、服务端Endpoint、服务账号（ServiceAccount）、命名空间（Namespace）、资源定额（Resoucequota）等的管理，当某一个节点宕机时，controller manager会及时发现故障并执行自动化修复流程，确保集群始终处于预期的工作状态。</p><h2 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h2><p>Controller Manager内部包含Replication Controller、Node Controller、Resourcequota Controller、Namespace Controller、ServiceAccount Controller、Token Controller、Service Controller、Endpoint Controller等多个Controller，每种Controller负责一种具体管控流程，而Controller manager是这些Controller的核心管理者。</p>',5),l=[t];function c(s,i,d,u,m,_){return o(),r("div",null,l)}const h=e(n,[["render",c]]);export{b as __pageData,h as default};
